+                            Some(idx)
+                        }
+                        FunctionArgs::List(_) => {
+                            return Err(FrankenError::NotImplemented(format!(
+                                "{func}() with multiple args is not supported in GROUP BY+JOIN path"
+                            )));
+                        }
+                    };
